55	/** Build the GitHub reviews API comments[] array from in-diff findings. Strays are demoted. */
56	export const buildInlineComments = (
57	  findings: readonly Finding[],
58	  diff: string,
59	  context: InlineContext,
60	): InlineResult => {
61	  const { inlineTemplate, models = [], jsonUrl, findings: fullFindings } = context;
62	  const index = indexDiff(diff);
63	  const { inDiff, strays } = partitionFindings(findings, index);
64	  const eta = new Eta({ autoTrim: false });
65	  const modelsText = formatModels(models);
66	
67	  const comments: InlineComment[] = inDiff.map((f) => {
68	    const pointer = fullFindings ? findingPointer(f, fullFindings.schema_version, jsonUrl) : "";
69	    const comment: InlineComment = {
70	      path: f.path,
71	      line: f.end_line,
72	      side: defaultSide(f.side),
73	      body: renderCommentBody(f, eta, inlineTemplate, modelsText, jsonUrl, pointer),
74	    };
75	    if (f.start_line < f.end_line) {
76	      return {
77	        ...comment,
78	        start_line: f.start_line,
79	        start_side: defaultSide(f.side),
80	      };
81	    }
82	    return comment;
83	  });
84	
85	  return { comments, strays, inDiff };
86	};
