180	/** Post the inline review, pointing its body at the sticky (issue #11) when the sticky's URL is
181	 *  known, and prepending the precomputed findings-json marker (issue #19) so the review body carries
182	 *  it too. `comments[i]` is the rendered comment for finding `inDiff[i]` (1:1, same order). Returns
183	 *  the review's `html_url` (undefined on a malformed response), how many inline comments actually
184	 *  posted, and the findings whose comment GitHub rejected — so the caller can surface exactly those
185	 *  in the sticky (issue #57) and keep the disposition count truthful (issue #21). */
186	const postInlineReview = async (
187	  repo: string,
188	  prNumber: number,
189	  headSha: string,
190	  comments: readonly InlineComment[],
191	  inDiff: readonly Finding[],
192	  stickyUrl: string | undefined,
193	  marker: string,
194	  ghApi: GhApi,
195	): Promise<{
196	  readonly url: string | undefined;
197	  readonly inlinePosted: number;
198	  readonly unposted: readonly Finding[];
199	}> => {
200	  const pointer = reviewBodyPointer(headSha, stickyUrl, marker);
201	  const reviewBody = (withComments: boolean): string =>
202	    JSON.stringify({
203	      body: pointer,
204	      commit_id: headSha,
205	      event: "COMMENT",
206	      comments: withComments ? comments.map(commentPayload) : [],
207	    });
208	  const reviewsEndpoint = [`repos/${repo}/pulls/${String(prNumber)}/reviews`, "--input", "-"];
209	  try {
210	    const stdout = await ghApi(reviewsEndpoint, reviewBody(true));
211	    return { url: parseHtmlUrl(stdout), inlinePosted: comments.length, unposted: [] };
212	  } catch (err) {
213	    // The reviews endpoint is atomic: one comment on a position GitHub won't accept rejects the WHOLE
214	    // batch (issue #57). Rather than fail the job — or drop every comment — post the review body-only
215	    // (so the event + findings marker exist) and then re-post each comment individually, keeping the
216	    // ones GitHub accepts and collecting the finding behind each one it rejects for the caller to
217	    // surface in the sticky. Degrade, never crash (§5.5). A body-only review that itself fails
218	    // (comments.length === 0) is a genuine error and propagates.
219	    if (comments.length === 0) throw err;
220	    process.stderr.write(
221	      `Warning: the batched inline review on PR #${String(prNumber)} was rejected (${err instanceof Error ? err.message : String(err)}) — GitHub rejects the whole batch if any one comment's position is invalid; posting the review body-only, then each comment individually to keep the valid ones (issue #57)\n`,
222	    );
223	    const url = parseHtmlUrl(await ghApi(reviewsEndpoint, reviewBody(false)));
224	    const commentsEndpoint = [`repos/${repo}/pulls/${String(prNumber)}/comments`, "--input", "-"];
225	    const unposted: Finding[] = [];
226	    let inlinePosted = 0;
227	    for (const [i, c] of comments.entries()) {
228	      try {
229	        await ghApi(commentsEndpoint, JSON.stringify({ commit_id: headSha, ...commentPayload(c) }));
230	        inlinePosted += 1;
231	      } catch (e) {
232	        const finding = inDiff[i];
233	        if (finding) unposted.push(finding);
234	        process.stderr.write(
235	          `Warning: inline comment on ${c.path}:${String(c.line)} rejected (${e instanceof Error ? e.message : String(e)}) — surfacing that finding in the sticky instead (issue #57)\n`,
236	        );
237	      }
238	    }
239	    return { url, inlinePosted, unposted };
240	  }
241	};
