313	/** Upsert the sticky summary — trust by author identity (bot login), not marker alone (§5.3).
314	 *  Returns the sticky's id + `html_url` (url undefined on a malformed response) so the caller can
315	 *  re-patch it with a link to the review once posted (issue #11). Returns null only when a *new*
316	 *  comment's response couldn't be parsed at all — there is then no id to re-patch with. */
317	const upsertSticky = async (
318	  repo: string,
319	  prNumber: number,
320	  existing: { readonly id: number; readonly body: string } | null,
321	  body: string,
322	  ghApi: GhApi,
323	): Promise<{ readonly id: number; readonly url: string | undefined } | null> => {
324	  if (existing !== null) {
325	    const patched = await patchComment(repo, existing.id, body, ghApi);
