316	 *  comment's response couldn't be parsed at all — there is then no id to re-patch with. */
317	const upsertSticky = async (
318	  repo: string,
319	  prNumber: number,
320	  existing: { readonly id: number; readonly body: string } | null,
321	  body: string,
322	  ghApi: GhApi,
323	): Promise<{ readonly id: number; readonly url: string | undefined } | null> => {
