370	/** Dismiss superseded bot-authored reviews (REC-CO-2). Failures are logged, never fail the job. */
371	const dismissReviews = async (
372	  repo: string,
373	  prNumber: number,
374	  ids: readonly number[],
375	  ghApi: GhApi,
376	): Promise<void> => {
377	  for (const id of ids) {
378	    try {
379	      await ghApi(
380	        [
381	          `repos/${repo}/pulls/${String(prNumber)}/reviews/${String(id)}/dismissals`,
382	          "-X",
383	          "PUT",
384	          "--input",
385	          "-",
386	        ],
387	        JSON.stringify({ message: "Superseded by a new review for an updated commit." }),
388	      );
389	    } catch (err) {
